const rectangle_limits: [9][2]usize = .{
    .{ 7, 7 },
    .{ 7, 16 },
    .{ 7, 33 },
    .{ 16, 7 },
    .{ 16, 16 },
    .{ 16, 33 },
    .{ 33, 7 },
    .{ 33, 16 },
    .{ 33, 33 },
};

const square_limits: [3]usize = .{
    7,
    16,
    33,
};

const alias_ops = .{ zsl.matrix.add_, zsl.matrix.sub_ };

test "zsl.matrix.apply2_" {
    @setEvalBranchQuota(3 * combinations.len);

    const allocator = std.testing.allocator;

    var prng = std.Random.DefaultPrng.init(@bitCast(std.time.timestamp()));
    const rand = prng.random();

    inline for (combinations) |combination| {
        const square = zsl.types.isSquareMatrix(combination[0]) or zsl.types.isSquareMatrix(combination[1]) or zsl.types.isSquareMatrix(combination[2]);
        const can_alias_B = combination[0] == combination[1];
        const can_alias_C = combination[0] == combination[2];

        const ops_to_test =
            if (comptime zsl.types.isNumeric(combination[1]))
                .{"mul"}
            else if (comptime zsl.types.isNumeric(combination[2]))
                .{ "mul", "div" }
            else
                .{ "add", "sub" };

        if (!square) {
            for (rectangle_limits) |mn| {
                try executeTestBlock(allocator, rand, combination, ops_to_test, mn[0], mn[1], false, false);
                if (can_alias_B) try executeTestBlock(allocator, rand, combination, ops_to_test, mn[0], mn[1], true, false);
                if (can_alias_C) try executeTestBlock(allocator, rand, combination, ops_to_test, mn[0], mn[1], false, true);
            }
        } else {
            for (square_limits) |m| {
                try executeTestBlock(allocator, rand, combination, ops_to_test, m, m, false, false);
                if (can_alias_B) try executeTestBlock(allocator, rand, combination, ops_to_test, m, m, true, false);
                if (can_alias_C) try executeTestBlock(allocator, rand, combination, ops_to_test, m, m, false, true);
            }
        }
    }
}

fn executeTestBlock(
    allocator: std.mem.Allocator,
    rand: std.Random,
    comptime combination: [3]type,
    comptime ops: anytype,
    m: usize,
    n: usize,
    comptime alias_B: bool,
    comptime alias_C: bool,
) !void {
    inline for (ops) |op| {
        var A = try tzsl.matrix.randomMatrix(combination[0], allocator, rand, m, n);
        defer A.deinit(allocator);

        var B = if (alias_B) try A.copy(allocator) else if (comptime zsl.types.isNumeric(combination[1])) tzsl.randomNumber(combination[1], rand) else try tzsl.matrix.randomMatrix(combination[1], allocator, rand, m, n);
        defer tzsl.deinit(allocator, &B);

        var C = if (alias_C) try A.copy(allocator) else if (comptime zsl.types.isNumeric(combination[2])) tzsl.randomNumber(combination[2], rand) else try tzsl.matrix.randomMatrix(combination[2], allocator, rand, m, n);
        defer tzsl.deinit(allocator, &C);

        const ptr_B = if (alias_B) A else B;
        const ptr_C = if (alias_C) A else C;

        if (comptime std.mem.eql(u8, op, "add"))
            zsl.matrix.add_(&A, ptr_B, ptr_C) catch unreachable
        else if (comptime std.mem.eql(u8, op, "sub"))
            zsl.matrix.sub_(&A, ptr_B, ptr_C) catch unreachable
        else if (comptime std.mem.eql(u8, op, "mul"))
            zsl.matrix.mul_(&A, ptr_B, ptr_C) catch unreachable
        else
            zsl.matrix.div_(&A, ptr_B, ptr_C) catch unreachable;

        var D = if (comptime std.mem.eql(u8, op, "add"))
            try tzsl.matrix.correctApply2(zsl.types.Numeric(combination[0]), allocator, m, n, B, C, zsl.numeric.add_)
        else if (comptime std.mem.eql(u8, op, "sub"))
            try tzsl.matrix.correctApply2(zsl.types.Numeric(combination[0]), allocator, m, n, B, C, zsl.numeric.sub_)
        else if (comptime std.mem.eql(u8, op, "mul"))
            try tzsl.matrix.correctApply2(zsl.types.Numeric(combination[0]), allocator, m, n, B, C, zsl.numeric.mul_)
        else
            try tzsl.matrix.correctApply2(zsl.types.Numeric(combination[0]), allocator, m, n, B, C, zsl.numeric.div_);
        defer D.deinit(allocator);

        tzsl.matrix.areEql(A, D) catch |e| {
            const aliasing = if (comptime alias_B) "B" else if (comptime alias_C) "C" else "no";
            std.debug.print("Failed on A: {s} = B: {s} {s} C: {s}, case m = {}, n = {}, aliasing = {s}\n", .{ @typeName(combination[0]), @typeName(combination[1]), op, @typeName(combination[2]), m, n, aliasing });
            return e;
        };
    }
}
